hljs.registerLanguage("gdscript", function (hljs) {
  "use strict";

  return {
    name: "GDScript",
    aliases: ["gd"],
    case_insensitive: false,
    keywords: {
      keyword: [
        "func",
        "var",
        "const",
        "if",
        "elif",
        "else",
        "for",
        "while",
        "match",
        "return",
        "break",
        "continue",
        "pass",
        "extends",
        "class",
        "class_name",
        "enum",
        "signal",
        "static",
        "is",
        "as",
        "not",
        "and",
        "or",
        "in",
        "self",
        "void",
        "await",
        "super",
        "get",
        "set",
      ].join(" "),
      literal: "true false null",
      type: [
        "int",
        "float",
        "String",
        "bool",
        "void",
        "Vector2",
        "Vector2i",
        "Vector3",
        "Vector3i",
        "Vector4",
        "Vector4i",
        "Color",
        "Rect2",
        "Rect2i",
        "Transform2D",
        "Transform3D",
        "Plane",
        "Quaternion",
        "AABB",
        "Basis",
        "Projection",
        "NodePath",
        "RID",
        "Object",
        "Callable",
        "Signal",
        "Dictionary",
        "Array",
        "PackedByteArray",
        "PackedInt32Array",
        "PackedInt64Array",
        "PackedFloat32Array",
        "PackedFloat64Array",
        "PackedStringArray",
        "PackedVector2Array",
        "PackedVector3Array",
        "PackedColorArray",
        "Variant",
        "Resource",
        "RefCounted",
        "Node",
        "StringName",
        "PackedScene",
        "GDActionContext",
        "GDQuestService",
        "GDCharacterService",
        "GDBattleService",
        "GDLightingService",
        "GDSceneNodeService",
        "GDInventoryService",
        "GDModRegistryService",
        "GDActionCharacter",
        "GDCharacter",
        "GDBattleResult",
        "GDItem",
      ].join(" "),
      built_in: [
        "print",
        "printerr",
        "prints",
        "printt",
        "printraw",
        "print_rich",
        "print_debug",
        "push_error",
        "push_warning",
        "instance",
        "free",
        "get_node",
        "is_instance_valid",
        "typeof",
        "type_exists",
        "str",
        "range",
        "len",
        "abs",
        "sign",
        "min",
        "max",
        "clamp",
        "clampf",
        "lerp",
        "lerpf",
        "round",
        "roundf",
        "floor",
        "floorf",
        "ceil",
        "ceili",
        "pow",
        "sqrt",
        "sin",
        "cos",
        "tan",
        "asinh",
        "acosh",
        "atanh",
        "asin",
        "acos",
        "atan",
        "atan2",
        "deg_to_rad",
        "rad_to_deg",
        "ease",
        "randi",
        "randf",
        "randf_range",
        "randi_range",
        "randfn",
        "randomize",
        "seed",
        "preload",
        "load",
        "resource_exists",
        "wrap",
        "wrapf",
        "wrapi",
        "move_toward",
        "is_equal_approx",
        "is_finite",
        "is_inf",
        "is_nan",
        "is_zero_approx",
        "snapped",
        "angle_difference",
      ].join(" "),
    },
    contains: [
      hljs.HASH_COMMENT_MODE,
      hljs.QUOTE_STRING_MODE,
      hljs.APOS_STRING_MODE,
      hljs.C_NUMBER_MODE,
      // @export, @onready, @tool, @icon etc.
      {
        scope: "meta",
        begin: /@\w[\w_]*/,
        relevance: 3,
      },
      // $ node paths and % unique names
      {
        scope: "selector-tag",
        begin: /\$"?[\w\/%]+"?/,
        relevance: 1,
      },
      {
        scope: "selector-id",
        begin: /%("[\w\s]+"|\w+)/,
        relevance: 1,
      },
      // func name(args) and method calls
      {
        scope: "title.function_",
        begin: /\b\w+(?=\s*\()/,
        relevance: 0,
      },
      // -> signal/return type
      {
        scope: "operator",
        begin: /->/,
        relevance: 0,
      },
      // Operators
      {
        scope: "operator",
        begin: /:=/,
        relevance: 0,
      },
    ],
  };
});
